int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    long long k;
    cin >> n >> k;
    vector<long long> a(n);
    for (int i = 0; i < n; i++) cin >> a[i];
    sort(a.begin(), a.end());

    int mid = n / 2;
    long long low = a[mid];
    long long high = a[mid] + k + 1;

    auto can = [&](long long x) {
        long long need = 0;
        for (int i = mid; i < n; i++) {
            if (a[i] < x) {
                need += x - a[i];
                if (need > k) return false;
            }
        }
        return true;
    };

    while (low + 1 < high) {
        long long m = low + (high - low) / 2;
        if (can(m)) low = m;
        else high = m;
    }

    cout << low << "\n";
    return 0;
}

