        cin >> op;
        if (op == "union") {
            int a, b;
            cin >> a >> b;
            dsu.unite(a, b);
        } else {
            int x;
            cin >> x;
            cout << dsu.size_of(x) << "\n";
        }
    }
    return 0;
}

